INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-10ced7e2-moex-00501', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-34c7f7f6', 'sub-elementary-10ced7e2-03', NULL, 'single_choice', '「臺灣物產的文獻紀錄，可考者最早可溯至 1607 年陳第的《東番記》，食用作物玉米、番 薯原產於美洲，據推測是從西班牙的殖民地菲律賓引入，再輾轉進入臺灣。也提到當時原住 民所種的甘蔗，可見甘蔗引進臺灣的時間很久遠，應是引自中國。檳榔等作物可能直接引自 中南半島。臺灣在納入了全球化的經濟貿易後，連帶的進入生態交流網絡之中。」 根據上文，下列選項正確的是：', '["臺灣並無原生食用植物，都是殖民者由島外引進栽種", "甘蔗很早就引進臺灣，顯見臺灣的製糖工業源遠流長", "全球交通、跨國貿易、殖民等因素，影響了飲食物產", "從物產判斷，中、菲、美洲是臺灣當時三大貿易夥伴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00502', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-34c7f7f6', 'sub-elementary-10ced7e2-03', NULL, 'single_choice', '一位醫師作家以當代的醫學角度思考詩仙李白為何如此愛喝酒而寫道：「李白聚會喝酒寫出 來的詩，統稱為『宴飲詩』，趁難得的美好時節與朋友相聚，在有限的年華暢飲，李白因此 寫下了 的千古名句。在詩中，他大力稱述飲酒的妙處，高聲讚揚及時行樂。這或許是 因為李白的腦部受到酒精影響，瀰漫著舒服愉悅的感覺。」 根據上文， 中最適合填入的詩句是：', '["舉頭望明月，低頭思故鄉", "蘭陵美酒鬱金香，玉碗盛來琥珀光", "人生得意須盡歡，莫使金樽空對月", "花間一壺酒，獨酌無相親，舉杯邀明月，對影成三人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00503', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-34c7f7f6', 'sub-elementary-10ced7e2-03', NULL, 'single_choice', '「你不會因為有了小孩就更有父母的樣子，就像擁有一架鋼琴不會讓你變成鋼琴家。」下列 選項，何者最符合文意？', '["只要開始，就有機會", "動機是最單純的力量", "有力的理由造成有力的行動", "付諸行動，從做中學累積成果"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00504', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-34c7f7f6', 'sub-elementary-10ced7e2-03', NULL, 'single_choice', '「用人不在於如何減少人的短處，而在於如何發揮人的長處。」下列選項，最符合文意的是：', '["大材不小用，小材不大用", "將適合的人請上車，不適合的人請下車", "能用他人智慧去完成自己工作的人是偉大的", "天生我材必有用，要能夠知人善任，因材器使"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00505', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-34c7f7f6', 'sub-elementary-10ced7e2-03', NULL, 'single_choice', '「一切美好的事物都有美麗的開頭。不過，真正懂得人生的人都知道，『美好的開頭使事情 成功了一半』並不真。這個世界到處是美好的開頭，同時也到處是『只成功了一半』的事業。 美好的開頭不能結美好的果實。真正使事業成功，使一個人有成就的，是無窮的耐心。」 下列選項，何者最符合上文的旨趣？', '["懂得珍惜的人才會成功", "持之以恆才是成功的關鍵", "美好的果實，總是令人期待", "美好的開始，是成功的一半"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00506', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-34c7f7f6', 'sub-elementary-10ced7e2-03', NULL, 'single_choice', '「如果有人要你數算一個罐子裡的泡泡糖數量，你肯定可以輕鬆算出來，甚至還樂於嚐嚐罐 子裡不同口味的糖果。然而，如果要你站在一座裝滿泡泡糖的游泳池前，必須數出所有的糖 果數量，你大概連試都不想試了。」 下列選項，何者最有可能是「連試都不想試」的原因？', '["數大就是美", "小處做起建立信心", "根本不可能完成任務", "在任務中無法找到樂趣"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00507', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-34c7f7f6', 'sub-elementary-10ced7e2-03', NULL, 'single_choice', '「人類從存在以來就有刻板印象，在古代，生存和保護有賴家族和部落。同族的人是安全的， 陌生人是危險的。陌生人通常被當作敵人，只因為他們的外表、言語或行為不同而已。消除 刻板印象其實只需站在對方的立場，生活一週、一天或甚至一小時就行了。在職場上，行銷 部和生產部的人應該交換工作幾天，或至少做角色互換。主管和員工也應該交換工作幾天， 有一些聰明的公司就是這麼做。這減少了不信任和溝通的問題，增加團隊合作和生產力，最 主要的問題常在於，來自某文化的人從未接觸過另一文化的人。」 根據上文，下列選項何者最符合文意？', '["打從人類歷史以來便有根深柢固的成見，改變不易", "先入為主的觀念，不會阻絕溝通管道形成刻板印象", "職場上的角色互換可以啟發人的同理心，消弭歧見", "文化的隔閡，很少是不同族群產生衝突的重要因素"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00508', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-34c7f7f6', 'sub-elementary-10ced7e2-03', NULL, 'single_choice', '「簡單是一種修煉，越是面對複雜情境的人，這修煉越必要。但若修煉得宜，過程其實充滿 了喜悅，因為複雜的是人的頭腦和習性，人的本性和本心，始終都是簡單的。修煉簡單，就 是找回真我，重返赤子之心，豈有不樂之理？」 根據上文，下列選項何者最符合文意？', '["人們都是用心多，用腦少，往往自尋煩惱", "簡單的事，想太多就複雜，凡事不想就好", "複雜的事，看淡了就簡單，看透了就輕鬆", "保持赤子童心，並非一種尋回真我的修煉"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00509', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-34c7f7f6', 'sub-elementary-10ced7e2-03', NULL, 'single_choice', '「人們平常傾向於二分法的思考，例如：好與壞；英雄對惡棍；我的國家與其他國家。記者 擅長把相異的人事物寫成對立，偏好報導赤貧與富豪。紀錄片喜歡描寫無名小卒如何對抗邪 惡的大企業，賣座大片通常是在拍正義與邪惡的對立。由於二分法直覺，我們往往在統合中 想像對立，在融匯中想像歧異，在一致中想像衝突。這種直覺處處可見，徹底扭曲認知。所 以當你觀看兩個群體對立的新聞時，也許會用到『鴻溝越來越大』等用語。」 根據上文，下列選項最符合文意的是：', '["傳統善惡分明的教育中，人們判斷事物只剩下好與壞、對與錯的觀點", "媒體往往以直觀的方式在對立與歧異中尋求統合融匯，以增加收視率", "二分法的思考模式容易遭人利用，讓有心人士去強化衝突，製造爭端", "正邪不兩立的觀點，充斥在人們日常生活中，也是拍攝電影的好題材"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00510', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-34c7f7f6', 'sub-elementary-10ced7e2-03', NULL, 'single_choice', '承上題，下列選項何者最接近作者所說二分法思考的傾向？', '["革命尚未成功，同志仍需努力", "人不可以貌相，海水不可斗量", "過度捕撈造成許多海洋生物瀕臨絕種", "未開發國家的疫苗接種率普遍都偏低"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL)
